sql:
SELECT name
FROM code_snippets
WHERE complexity = (SELECT MAX(complexity) FROM code_snippets);

SELECT evaluation_date, score
FROM code_evaluations
ORDER BY evaluation_date DESC;

SELECT COUNT(*) 
FROM code_evaluations 
WHERE evaluator_id = 0;

SELECT name, size
FROM code_snippets
WHERE duplication > (SELECT threshold FROM duplication_metrics WHERE metric_name = 'Function Duplication');

SELECT evaluation_date
   FROM code_evaluations
   WHERE status = 'completed';

SELECT name
FROM code_snippets
WHERE duplication > (SELECT threshold FROM duplication_metrics WHERE duplication_id = 0);

SELECT name, complexity
FROM code_snippets
ORDER BY complexity DESC;

external_knowledge:
- 'code artisans' refers to developers who have submitted code snippets; 
- 'top 3' means the highest ranked developers within each project based on their average evaluation score; 
- 'average evaluation score' is a measure of a developer's performance and is calculated by averaging the scores from all evaluations of their code snippets.
